window.OFFICIAL_EXAMS = [{"name":"PEE Junio 1","code":"B0626PEE-1","date":"20/06/2026","questions":[{"q":"Com s’anomena l’element estructural que prolonga la quilla en direcció vertical o inclinada per la part de proa? /¿Cómo se llama el elemento estructural que prolonga la quilla en dirección vertical o inclinada por la parte de proa?","a":["Bao. / Bao.","Codast. / Codaste.","Orsa. / Orza.","Roda. / Roda."],"c":3},{"q":"Com s’anomena la part de l’embarcació del dibuix assenyalada amb una fletxa? / ¿Cómo se denomina la parte de la embarcación del dibujo señalada con una flecha?","a":["Aleta de estribord. / Aleta de estribor.","Amura de babor. / Amura de babor.","Codast. / Codaste.","Aleta de babor / Aleta de babor"],"c":3},{"q":"Com s’anomena el torn horitzontal col·locat en direcció de babord a estribord sobre la coberta de proa d'un vaixell i que serveix per a llevar les àncores? / ¿Cómo se llama el torno horizontal colocado en dirección de babor a estribor sobre la cubierta de proa de un barco y que sirve para levar las anclas?","a":["Escobenc / Escobén","Molinet / Molinete","Danforth / Danforth","Cabiró / Cabirón"],"c":1},{"q":"On van a parar tots el vessaments de líquids produïts a l’interior de l’embarcació? / ¿Dónde van a parar todos los derrames de líquidos producidos en el interior de la embarcación?","a":["A la coberta./ A la cubierta","A la sentina./ A la sentina","A l’enfogonament./ A la fogonadura","Al trancanell./ Al trancanil  UT2 Elements d’amarratge i fondeig/ UT2 Elementos de amarre y fondeo (5-6)"],"c":1},{"q":"Què haurem de fer per saber on queda fondejada l’àncora? / ¿Qué deberemos hacer para saber dónde queda fondeada el ancla?","a":["Arrelar-la. / Arraigarla.","Mesurar la fondària. / Medir la profundidad.","Contar les baules. / Contar los eslabones.","Orincar-la. / Orincarla."],"c":3},{"q":"Quin tipus de nus preferentment faríem servir per afermar una amarra a una ar - golla? /¿Qué tipo de nudo preferentemente haríamos servir para afirmar una amarra a una argolla?","a":["Volta de ruixó./ Vuelta de rezón.","Nus de pardal./ Ballestrinque","As de guia./ As de guia.","Nus pla./ Nudo llano"],"c":0},{"q":"Quin tipus de maniobra o exploració farem en cas de NO veure a la persona que hagi caigut a l’aigua? / ¿Qué tipo de maniobra o exploración haremos en caso de NO ver a la persona que haya caido al agua?.","a":["Maniobra de Williamson. / Maniobra de Williamson.","Maniobra de Anderson./ Maniobra de anderson.","Exploració en espiral cuadrada. / Exploración en espiral cuadrada","Maniobra de Boutakov. / Maniobra de de Boutakov."],"c":2},{"q":"Què vol dir l’expressió a “so de mar”? / ¿Qué quiere decir la expresión “a son de mar”?","a":["Que aguantem un temporal amurats a la mar. / Que aguantamos un temporal amurados a la mar.","Que navegarem de popa o aleta per capejar el temporal. / Que navegaremos de popa o aleta para capear el temporal.","Que l’estiba, l’arranjat i el trincat s´han fet amb criteri i a consciència./ Que la estiba, arranchado y el trincado se han hecho con criterio y a conciencia.","Que naveguem síncrones al ritme de les onades. / Que navegamos síncronos al ritmo del oleaje."],"c":2},{"q":"En cas de navegar a motor intraborda amb mal temps, com haurem de tenir les aixetes de fons ? / En caso de navegar a motor intraborda con mal tiempo, ¿Cómo habrán de estar los grifos de fondo?","a":["Hauran d’estar tots tancats./ Tendrán que estar todos cerrados.","Hauran d’estar tots tancats excepte el de refrigeració del motor./ Habrán de estar todos cerrados excepto el de refrigeración del motor","Hauran d’estar tots tancats excepte els de buidats de sentina i desguàs de l’aigüera./ Habrán de estar todos cerrados excepto los de vaciado de sentina y desagüe del fregadero","Hauran d’estar tots oberts excepte el de refrigeració del motor./ Habrán de estar todos cerrados excepto el de refrigeración del motor"],"c":1},{"q":"Què son les aigües someres? / ¿Qué son las aguas someras?","a":["Aigües en les quals la profunditat és menor que la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la longitud de la ola superficial.","Aigües en les quals la profunditat és més gran que la meitat de la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.","Aigües en les quals la profunditat és més gran que la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.","Aigües en les quals la profunditat és menor que la meitat de la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.  UT4 Legislació / UT4 Legislación (11-12)"],"c":3},{"q":"Quina restricció legislativa a les platges abalisades és la correcta? / ¿Qué restricción legislativa en las playas balizadas es la correcta?","a":["Queda prohibida l’entrada de qualsevol tipus d’embarcació o artefacte flotant / Queda prohibida la entrada de cualquier tipo de embarcación o artefacto flotante","Queda prohibida l’entrada i el fondeig de qualsevol tipus d’embarcació o artefacte flotant / Queda prohibida la entrada y el fondeo de cualquier tipo de embarcación o artefacto flotante.","Es permet la navegació d’embarcacions a velocitat no superior a 3 nusos / Se permite la navegación de embarcaciones a velocidad no superior a 3 nudos.","Es permet la navegació de motos d’aigua a velocitat no superior a 3 nusos / Se permite la navegación de notos de agua a velocidad no superior a 3 nudos."],"c":1},{"q":"Quina és la mínima distància de seguretat que hauríem de mantenir de la zona de busseig? / ¿Cual es la distancia mínima de seguridad que debemos mantener de la zona de buceo?.","a":["150 metres / 150 metros","100 metres / 100 metros","75 metres / 75 metros","50 metres / 50 metros"],"c":3},{"q":"Què ens indica la balisa de la figura?. ¿Qué nos indica la baliza de la figura?","a":["Aigües navegables./ Aguas navegables.","Perill aïllat./ Peligro aislado.","Marques especials./ Marcas especiales.","Aigües navegables pel quadrant nord / Aguas navegables por el cuadrante norte"],"c":1},{"q":"Al SORTIR de la bocana d’un port, abalisat amb el sistema lateral, a quina banda deixarem les marques? / Al SALIR a la bocana de un puerto, balizado por el sistema lateral, ¿A qué banda deberemos dejar las marcas?.","a":["La marca verda per babord i la vermella per babord./ La marca verde por babor y la roja por babor.","La marca vermella per babor i la verda por estribor/ La marca roja por babor y la verde por estribor.","La marca vermella per estribord i la verda per babord / La marca roja por estribor y la verde por babor.","La marca verda per estribord i la vermella per estribord / La marca verde por estribor y la roja por estribor"],"c":2},{"q":"Què ens indica la balisa que apareix en el dibuix amb franges vermelles i una verda al centre? / ¿Qué nos indica la baliza que aparece en el dibujo con franjas rojas, una verde en el centro?","a":["Aigües navegables al seu voltant. / Aguas navegables a su alrededor.","Prohibida la navegació en aquesta àrea. / Prohibida la navegación en esta área.","Canal principal a babord. / Canal principal a babor.","Canal principal a estribord. / Canal principal a estribor"],"c":3},{"q":"Quina és la marca de topall de la boia que ens indica un abocador? / ¿Cuál es la marca de tope de la boya que nos indica un vertedero?","a":["Dos cons negres. / Dos conos negros.","Una aspa groga en forma d’ics. / Un aspa amarilla en forma de ics.","Una esfera vermella. / Una esfera roja.","Dues esferes negres. / Dos esferas negras."],"c":1},{"q":"Què ens indica la balisa que té una esfera vermella al capdamunt?/ ¿Qué nos indica la baliza que tiene una esfera roja de tope?","a":["Un perill nou. / Un peligro nuevo.","Un perill aïllat. / Un peligro aislado.","Aigües navegabes al voltant de la balisa./ Aguas navegables alredeor de la baliza.","Balisa on puc amarrar-me. / Baliza donde puedo amarrarme. UT6 Reglament (RIPA) / UT6 Reglamento (RIPA) (18-27)"],"c":2},{"q":"Navegant en un vaixell de vela i rebent el vent per babord, albirem un altre vai - xell de vela per sobrevent, que rep el vent per estribord i s’aproxima amb risc d’abordatge. Qui té l’obligació de maniobrar i per què? / Navegando en un buque de vela y recibiendo el viento por babor, divisamos otro buque de vela por barlovento, que recibe el viento por estribor y se aproxima con riesgo de abordaje. ¿Quién tiene la obliga - ción de maniobrar y por qué?","a":["L’altre, perquè es troba a sobrevent. / El otro, porque se encuentra a barlovento.","Nosaltres, perquè ens trobem a sotavent. / Nosotros, porque nos encontramos a sotavento.","Nosaltres, perquè rebem el vent per babord. / Nosotros, porque recibimos el viento por babor.","L’altre, perquè rep el vent per estribord . / El otro, porque recibe el viento por estribor."],"c":2},{"q":"A i B representen dues embarcacions de propulsió mecànica en una situació d’encreuament amb risc d’abordatge. Quina maniobra, d’acord amb el RIPA, farà l’embarcació B? / A y B representan dos embarcaciones de propulsión mecánica en una situación de cruce con riesgo de abordaje. ¿Qué maniobra, de acuerdo con el RIPA, hará la embarcación B?","a":["Es mantindrà apartada de la derrota de B. / Se mantendrá apartada de la derrota de B.","Mantindrà el seu rumb i la seva velocitat. / Mantendrá su rumbo y su velocidad.","Només maniobrarà quan B sigui un vaixell de vela. / Solo maniobrará cuando B sea un barco de vela.","Emetrà cinc xiulades curtes per cridar l’atenció de B. / Emitirá cinco pitadas cortas para llamar la atención de B. Vermell/Rojo"],"c":1},{"q":"Com es considera, segons el RIPA, la situació de l’embarcació \"A\" respecte a l’embarcació \"B\" del dibuix?/. ¿Cómo se considera, según el RIPA, la situación de la embarcación \"A\" respecto de la embarcación \"B\" del dibujo?","a":["De rumb oposat. / De vuelta encontrada.","Embarcació que abasta. / Embarcación que alcanza.","Embarcació que segueix a rumb. / Embarcación que sigue a rumbo.","De volta creuada. / De vuelta cruzada."],"c":1},{"q":"A i B representen dues embarcacions navegant exclusivament a vela. Qui té l’obligació de maniobrar? / A y B representan dos embarcaciones navegando exclusi - vamente a vela. ¿Quién tiene la obligación de maniobrar?","a":["A, perquè rep el vent per estribord. / A, porque recibe el viento por estribor.","B, perquè rep el vent per babord./ B, porque recibe el viento por babor.","Les dues embarcacions cauran a estribord perquè és una situació de rumb oposat. / Las dos embarcaciones caerán a estribor porque es una situación de vuelta encontrada.","A, perquè es troba a sobrevent. / A, porque se encuentra a barlovento."],"c":1},{"q":"Navegant en un vaixell de propulsió mecànica observem per la proa un vaixell de vela, i com mostra el dibuix, està creuant amb risc d’abordatge. Quina maniobra haurem d’efectuar? / Navegando en un buque de propulsión mecánica observamos por la proa un buque de vela, y como aparece en el dibujo, está cruzando con riesgo de abordaje. ¿Qué maniobra deberemos efectuar?","a":["Mantenir el rumb i la velocitat perquè tenim preferència de pas. / Mantener el rumbo y la velocidad porque tenemos preferencia de paso.","Maniobrarem per evitar l’abordatge. / Maniobraremos para evitar el abordaje.","Només maniobrarem si rebem el vent per estribord. / Solamente maniobraremos si recibimos el viento por estribor.","Només maniobrarem si rebem el vent per babord. / Solamente maniobraremos si recibimos el viento por babor."],"c":1},{"q":"De quin color és el llum de remolc? / ¿De qué color es la luz de remolque?","a":["Verd. / Verde.","Vermell. / Roja.","Blanc. / Blanca.","Groc. / Amarilla."],"c":3},{"q":"Quin tipus de vaixell porta hissada una marca bicònica negra (dos cons units per la base)? / ¿Qué tipo de buque lleva izada una marca bicónica negra (dos conos unidos por la base)?","a":["Vaixell remolcador amb la longitud del remolc superior a 200 metres. / Buque remolcador con la longitud del remolque superior a 200 metros.","Veler navegant a vela i motor / Velero navegando a vela y motor","Pesquer d’encerclament amb l’art estès a més de 150 metres del vaixell. / Pesquero de cerco con el arte extendido a más de 150 metros del buque.","Restringit pel seu calat. / Restringido por su calado."],"c":0},{"q":"Quin tipus de vigilància hem d’efectuar quan estem fondejats amb boira, segons el RIPA?/. ¿Qué tipo de vigilancia debemos de efectuar cuando estamos fondeados con niebla, según el RIPA?","a":["Visual i auditiva. / Visual y auditiva.","Només farem atenció de la pantalla del radar. / Solo prestaremos atención a la pantalla del radar.","Només auditiva. / Solo auditiva.","No fa falta efectuar cap tipus de vigilància. / No hace falta efectuar ningún tipo de vigilancia."],"c":0},{"q":"Què ens indica un vaixell que porta hissada, a la part de proa, una marca consistent en una bola negra? / ¿Qué nos indica un buque que lleva izada, en la parte de proa, una marca consistente en una bola negra?","a":["Que és un vaixell sense govern. / Que es un buque sin gobierno.","Que és un vaixell embarrancat de 12 metres d’eslora o més. / Que es un buque varado de 12 metros de eslora o más.","Que és un vaixell fondejat. / Que es un buque fondeado.","Que és un vaixell amb capacitat de maniobra restringida. / Que es un buque con capacidad de maniobra restringida."],"c":2},{"q":"Quina maniobra hem de realitzar si, entrant a port, observem per la proa una draga que exhibeix les marques del dibuix representat? / ¿Qué maniobra deberemos efectuar si, entrando a puerto, observamos por la proa una draga que exhibe las marcas del dibujo representado?","a":["Caurem a estribord. / Caeremos a estribor.","Caurem a babord o a estribord indistintament. / Caeremos a babor o a estribor indistintamente.","Continuarem a rumb. / Continuaremos a rumbo.","La deixarem per la nostra banda d’estribord. / La dejaremos por nuestra banda de estribor."],"c":0},{"q":"Quins caps s’han de reforçar quan estem atracats estribord al moll i ens informen que hi haurà vent de popa? / ¿Qué cabos hay que reforzar si estamos atracados estribor al muelle y nos informan que habrá viento de popa?","a":["Llarg de proa i espring de popa. / Largo de proa y esprín de popa.","Llarg de popa i través de proa. / Largo de popa y través de proa.","Llarg de popa i espring de proa. / Largo de popa y esprín de proa.","Llargs de proa i popa. / Largos de proa y popa."],"c":2},{"q":"Què significa el terme “lascar”? / ¿Qué significa el término “lascar”?","a":["Deixar anar una mica un cap que està treballant. / Soltar un poco un cabo que está trabajando.","Tirar d’un cap i anar-lo recollint. / Tirar de un cabo e irlo recogiendo.","Recollir un cap enrotllant-lo sobre ell mateix. / Recoger un cabo enrollándolo sobre sí mismo.","Subjectar un cap mitjançant una bossa. / Sujetar un cabo mediante una boza.  UT8 Emergències a la mar / UT8 Emergencias en la mar (30-32)"],"c":0},{"q":"Quines mesures prendrem en cas de tenir una embarrancada involuntària? ¿Qué medidas tomaremos en caso de sufrir una varada involuntaria?","a":["Farem màquina enrere immediatament amb el timó a la via. / Daremos màquina atrás inmediatamente con el timón a la vía.","Fixarem la nostra posició mitjançant una boia. / Fijaremos nuestra posición mediante una boya.","Prepararem l’àncora de capa. / Prepararemos el ancla de capa.","Analitzarem la qualitat del fons i les possibles avaries del buc. / Analizaremos la calidad del fondo y las posibles averías del casco."],"c":3},{"q":"Per quina zona de l’embarcació utilitzarem sempre les bengales o els coets? ¿Por qué zona de la embarcación utilizaremos siempre las bengalas o los cohetes?","a":["Per babord. / Por babor.","Per la proa. / Por la proa.","Per sobrevent. / Por barlovento.","Per sotavent. / Por sotavento."],"c":3},{"q":"Quins procediments bàsics cal seguir en la lluita contra incendis? ¿Qué procedimientos básicos se deben seguir en la lucha contra incendios?","a":["Refredament, localització i sufocació. / Enfriamiento, localización y sofocación","Localització, confinament i extinció. / Localización, confinamiento y extinción.","Sufocació, confinament i refredament. / Sofocación, confinamiento y enfriamiento.","Extinció, refredament i localització. / Extinción, enfriamiento y localización.  UT9 Meteorologia / UT9 Meteorología (33-36)"],"c":1},{"q":"Com s’anomenen les línies que uneixen els punts d’igual pressió atmosfèrica en un moment determinat? ¿Cómo se denominan las líneas que unen los puntos de igual presión atmosfèrica en un momento determinado?","a":["Isotermes. / Isotermas.","Isoclines. / Isoclinas.","Isòbates. / Isóbatas.","Isòbares. / Isóbaras."],"c":3},{"q":"Com giren els vents a l’hemisferi nord al voltant dels centres de baixes pressions? ¿Cómo giran los vientos en el hemisferio norte alrededor de los centros de bajas presiones?","a":["En sentit horari. / En sentido horario.","En sentit contrari a les agulles del rellotge. / En sentido contrario a las agujas del reloj.","De nord a sud. / De norte a sur.","D’est a oest. / De este a oeste."],"c":1},{"q":"Com es desplacen les borrasques, en general, a l’hemisferi nord? ¿Cómo se desplazan las borrascas, en general, en el hemisferio norte?","a":["D’est a oest. / De este a oeste.","Durant el dia d’oest a est i per la nit d’est a oest. / Durante el día de oeste a este y por la noche de este a oeste.","D’oest a est. / De oeste a este.","Durant l’estiu d’est a oest i a l’hivern d’oest a est. / Durante el verano de este a oeste y en invierno de oeste a este."],"c":2},{"q":"A què són degudes les marinades? ¿A qué son debidas las virazones?","a":["A que per la nit la terra es refreda més ràpidament que el mar. / A que por la noche la tierra se enfría más deprisa que el mar.","A que per la nit el mar es refreda més ràpidament que la terra. / A que por la noche el mar se enfría más deprisa que la tierra.","A que durant el dia el mar s’escalfa més ràpidament que la terra. / A que durante el día el mar se calienta más deprisa que la tierra.","A que durant el dia la terra s’escalfa més ràpidament que el mar. / A que durante el día la tierra se calienta más deprisa que el mar.  UT10 Teoria de navegació / UT10 Teoría de navegación (37-41)"],"c":3},{"q":"Quin és el valor màxim que pot tenir la latitud? ¿Cuál es el valor máximo que puede tener la latitud?","a":["90º","180º","180º N","36º 20’"],"c":0},{"q":"Què és la longitud? ¿Qué es la longitud?","a":["L’arc d’equador comprès entre el meridià de Greenwich i el meridià del lloc. / El arco de ecuador comprendido entre el meridiano de Greenwich y el meridiano del lugar.","L’arc de paral·lel comprès entre el meridià de Greenwich i el meridià del lloc. / El arco de paralelo comprendido entre el meridiano de Greenwich y el meridiano del lugar.","L’arc de meridià comprès entre el pol i el lloc. / El arco de meridiano comprendido entre el polo y el lugar.","L’arc de meridià comprès entre l’equador i el lloc. / El arco de meridiano comprendido entre el ecuador y el lugar."],"c":0},{"q":"Què representa el símbol de la imatge, utilitzat en les cartes nàutiques? ¿Qué representa el símbolo de la imagen, utilizado en las cartas náuticas?","a":["Reserva marina. / Reserva marina.","Granja marina. / Granja marina.","Àrea prohibida de pesca. / Área prohibida de pesca.","Ancoratge prohibit. / Fondeadero prohibido."],"c":2},{"q":"Quin és el valor que representa el període característic del següent far: Gp Oc (2) 6s 11m 9M? ¿Cuál es el valor que representa el periodo característico del siguiente faro: Gp Oc (2) 6s 11m 9M?","a":["Gp OC","6s","11m","9M"],"c":1},{"q":"Quina és la demora vertadera (Dv) del far del cap de Tortosa si navegant al rumb vertader (Rv) = 180º observem el far pel través de estribord? ¿Cuál es la demora verdadera (Dv) del faro del cabo de Tortosa si navegando al rumbo verdadero (Rv) = 180º observamos el faro por el través de estribor?","a":["090º","180º","270º","000º"],"c":2},{"q":"A trenc d’alba del dia 20 de juny del 2026 ens trobem a l’oposició dels fars de PUNTA CARNERO i PUNTA ALMINA, i a una distància de 6 milles del far de PUNTA EUROPA. Quina serà la nostre situació? Al amanecer del día 20 de junio del 2026 nos encontramos en la oposición de los faros de PUNTA CARNERO y PUNTA ALMINA, y a una distancia de 6 millas del faro de PUNTA EUROPA. ¿Cuál será nuestra situación?","a":["l = 36º 01,4’ N – L = 005º 27,2' W","l = 36º 02,0’ N – L = 005º 25,0' W","l = 35º 02,2’ N – L = 006º 22,4' W","l = 36º 01,0’ N – L = 005º 22,4' W"],"c":3},{"q":"El dia 20 de juny del 2026, sent HRB = 14:00, el vaixell ARKAN UNO es troba en la situació l = 35º 50,0’ N i L = 005º 50,0’ W, navegant amb un rumb d’agulla (Ra) = 315º i a una velocitat de 6 nusos. Quina serà la seva situació (posició) a HRB = 16:30? Correcció total per a aquest rumb (ct) = – 5º. El día 20 de junio del 2026, siendo HRB = 14:00, el barco ARKAN UNO se encuentra en la situación l = 35º 50,0’ N y L = 005º 50,0’ W, navegando con un rumbo de aguja (Ra) = 315º y a una velocidad de 6 nudos. ¿Cuál será su situación (posición) a HRB = 16:30? Corrección total para este rumbo (ct) = – 5º.","a":["l = 36º00,6’ N L = 006º04,1’ E","l = 35º56,9 N L = 006º02,4’ W","l = 35º58,6’ N L = 006º00,6’ E","l = 35º59,6’ N L = 006º04,2’ W"],"c":3},{"q":"Quin abast lumínic té un far situat a l = 36º 06,6' N i L = 005º 20,6' W? ¿Qué alcance lumínico tiene un faro situado en l = 36º 06,6' N y L = 005º 20,6' W?","a":["13 milles. / 13 millas.","10 milles. / 10 millas.","19/15 milles. / 19/15 millas.","19 milles. / 19 millas."],"c":2},{"q":"Quina serà la nostra situació si, navegant al rumb vertader (Rv) = 047 º, prenem marcació del far de PUNTA EUROPA (M) = 090º babord i la distància a aquest far és de 5,6 milles? ¿Cuál será nuestra situación si, navegando al rumbo verdadero (Rv) = 047º, tomamos marcación del faro de PUNTA EUROPA (M) = 090º babor y la distancia a este faro es de 5,6 millas?","a":["l = 36º 02,8’ N – L = 005º 25,6 W","l = 36º 02,5’ N – L = 005º 15,8 W","l = 36º 10,8’ N – L = 005º 15,8 W","l = 36º 01,9’ N – L = 005º 15,2 W"],"c":1}]},{"name":"PEE Junio 2","code":"B0626PEE-2","date":"20/06/2026","questions":[{"q":"Com s’anomena l’element estructural que prolonga la quilla en direcció vertical o inclinada per la part de popa? / ¿Cómo se llama el elemento estructural que prolonga la quilla en dirección vertical o inclinada por la parte de popa?","a":["Bao. / Bao.","Codast. / Codaste.","Orsa. / Orza.","Roda. / Roda."],"c":1},{"q":"Com van ubicades les hèlixs bessones de gir a l’exterior? / ¿Cómo van ubicadas las hélices gemelas de giro al exterior?","a":["La dextrogira a la banda de estribord i la levogira a la banda de babord / La dextrógira a la banda de estribor y la levógira a la banda de babor.","La dextrogira a la banda de babord i la levogira a la banda de estribord / La dextrógira a la banda de babor y la levógira a la banda de estribor.","La dextrogira a la banda de estribord i la levogira a la banda de estribord / La dextrógira a la banda de estribor y la levógira a la banda de estribor.","La dextrogira a la banda de babord i la levogira a la banda de babord / La dextrógira a la banda de babor y la levógira a la banda de babor."],"c":0},{"q":"Com s’anomena l’acció de cobrar la cadena de l’àncora amb el molinet? / ¿Cómo se denomina la acción de cobrar la cadena del ancla con el molinete?","a":["Llevar. / Zarpar.","Filar. / Filar.","Afermar. / Afirmar.","Virar. / Virar."],"c":3},{"q":"Quin assentament tenim, expressat en metres, si el nostre calat a proa és de 0,95 metres i el de popa és de 1,35 metres? / ¿Qué asiento tenemos, e x p r e s a d o en metros, si nuestro calado a proa es de 0,95 metros y el de popa es de 1,35 metros?","a":["2,30 empopant. / 2,30 apopante.","0,55 emproant. / 0,55 aproante.","0,60 empopant. / 0,60 apopante.","0,40 empopant. / 0,40 apopante.  UT2 Elements d’amarratge i fondeig / UT2 Elementos de amarre y fondeo (5-6)"],"c":3},{"q":"Què és el politjó? /¿Qué es la roldana?","a":["Roda giratòria que facilita el llavorament dels caps/. Rueda giratória que facilita el laboreo de los cabos.","Peça sòlida afermada a coberta per amarrar caps / Pieza sólida afirmada en cubierta para amarrar cabos.","Accessori que serveix de protecció contra els cops proa. / Accesorio que sirve de protección contra los golpes a proa.","És una màquina de llevar. / Es una máquina de levar."],"c":0},{"q":"Quin tipus de nus preferentment faríem servir per afermar una defensa al passa - mans del vaixell? /¿Qué tipo de nudo preferentemente haríamos para afirmarlo al pasa - manos de la embarcación?","a":["As de guia./ As de guia.","Nus pla./ Nudo llano","Volta de ruixó./ Vuelta de rezón.","Nus de pardal./ Ballestrinque"],"c":3},{"q":"Com millorem la estabilitat d’una embarcació? / ¿Cómo mejoramos la estabilidad de una embarcación?","a":["Desplaçant pesos cap a la quilla / Desplazando pesos hacia la quilla","Desplaçant pesos cap a coberta / Desplazando pesos hacia cubierta","Desplaçant pesos cap a proa / Desplazando pesos hacia proa","Desplaçant pesos cap a una banda / Desplazando pesos hacia una banda"],"c":0},{"q":"Què vol dir l’expressió a “so de mar”? / ¿Qué quiere decir la expresión “a son de mar”?","a":["Que aguantem un temporal amurats a la mar. / Que aguantamos un temporal amurados a la mar.","Que navegarem de popa o aleta per capejar el temporal. / Que navegaremos de popa o aleta para capear el temporal.","Que l’estiba, l’arranjat i el trincat s´han fet amb criteri i a consciència./ Que la estiba, arranchado y el trincado se han hecho con criterio y a conciencia.","Que naveguem síncrones al ritme de les onades. / Que navegamos síncronos al ritmo del oleaje."],"c":2},{"q":"Com sabem que una aixeta de fons està totalment tancada? / ¿Cómo sabemos que un grifo de fondo está completamente cerrado?.","a":["Quan la manilla està paral·lela respecte a la direcció del tub./ Cuando la maneta está paralela respecto a la dirección del tubo.","Quan la manilla està perpendicular respecte a la direcció del tub./ Cuando la maneta está perpendicular respecto a la dirección del tubo.","Quan la manilla està a 45° respecto a la direcció del tub./ Cuando la maneta esté a 45° respecte a la dirección del tubo.","Les aixetes de fons no tenen maneta per que sempre estan tancades./ Los grifos de fondo no tienen maneta por que siempre están cerrados"],"c":1},{"q":"Què son les aigües someres? / ¿Qué son las aguas someras?","a":["Aigües en les quals la profunditat és menor que la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la longitud de la ola superficial.","Aigües en les quals la profunditat és més gran que la meitat de la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.","Aigües en les quals la profunditat és més gran que la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.","Aigües en les quals la profunditat és menor que la meitat de la longitud de l'ona superficial./ Aguas en las cuales la profundidad es menor que la mitad de la longitud de la ola superficial.  UT4 Legislació / UT4 Legislación (11-12)"],"c":3},{"q":"A partir de quina distància de terra es pot descarregar al mar oli, combustible o altres hidrocarburs? / A partir de qué distancia de tierra se puede descargar al mar aceite, combustible u otros hidrocarburos?","a":["A partir de 3 milles previ tractament / A partir de 3 millas previo tratamiento.","A partir de 12 milles previ tractament / A partir de 12 millas previo tratamiento.","A partir de 24 milles previ tractament / A partir de 24 millas previo tratamiento.","Queda prohibit descarregar aquests productes a la mar / Está prohibido descargar estos productos al mar."],"c":3},{"q":"Com s’anomenen, d’acord amb el Conveni MARPOL, les aigües procedents de la tassa del vàter? / ¿Cómo se llaman, de acuerdo con el Convenio MARPOL, las aguas procedentes de la taza del inodoro?","a":["Aigües tòxiques. / Aguas tóxicas.","Aigües contaminants. / Aguas contaminantes.","Aigües residuals. / Aguas residuales.","Aigües brutes. / Aguas sucias.  UT5 Abalisament / UT5 Balizamiento (13-17)"],"c":3},{"q":"Navegant al rumb est, observem per la proa una boia groga i negra que com a marca de cap té dos cons negres sobreposats amb els vèrtexs cap abaix. Quin és el quadrant navegable respecte a la boia? / Navegando al rumbo oeste, observamos por la proa una boya amarilla y negra cuya marca de tope son dos conos negros superpuestos con los vértices hacia abajo. ¿Cuál es el cuadrante navegable respecto a la boya?","a":["Nord. / Norte.","Est. / Este.","Sud. / Sur.","Oest. / Oeste. Groc/Amarillo Negre/Negro Negre/Negro"],"c":2},{"q":"A l’ENTRAR a la bocana d’un port, abalisat amb el sistema lateral, a quina banda deixarem les marques? / Al ENTRAR a la bocana de un puerto, balizado por el sistema lateral, ¿A qué banda deberemos dejar la marca?.","a":["La marca verda per babord i la vermella per babord./ La marca verde por babor y la roja por babor.","La marca vermella per babor i la verda por estribor/ La marca roja por babor y la verde por estribor.","La marca vermella per estribord i la verda per babord / La marca roja por estribor y la verde por babor.","La marca verda per estribord i la vermella per estribord / La marca verde por estribor y la roja por estribor."],"c":1},{"q":"Entrant a un port situat a la regió A observem per la nostra banda d’estribord una balisa verda com la que apareix en el dibuix. Quina maniobra haurem d’efectuar? / Entrando a un puerto situado en la región A observamos por nuestra banda de estribor una baliza verde como la que aparece en el dibujo. ¿Qué maniobra deberemos efectuar?","a":["Caurem a estribord. / Caeremos a estribor.","Caurem a babord o a estribord indistintament. / Caeremos a babor o a estribor indistintamente.","Continuarem a rumb. / Continuaremos a rumbo.","La deixarem per la nostra banda de babord. / La dejaremos por nuestra banda de babor."],"c":2},{"q":"Quina és la marca de topall de la boia que ens indica una instal·lació d’aqüicultura? / ¿Cuál es la marca de tope de la boya que nos indica una instalación de acuicultura?","a":["Dos cons negres","Una aspa groga en forma d’ics","Dues esferes negres","Una esfera vermella"],"c":1},{"q":"De quin color és el llum de la marca d’aigües navegables? / ¿De qué color es la luz de la marca de aguas navegables?","a":["Blanc i vermell. / Blanca y roja.","Vermell. / Roja.","Blanc/ Blanco","Groc. / Amarilla."],"c":2},{"q":"Navegant en un vaixell de vela i rebent el vent per babord, albirem un altre vaixell de vela per sobrevent, que rep el vent també per babord i s’aproxima amb risc d’abordatge. Qui té l’obligació de maniobrar? / Navegando en un buque de vela y re - cibiendo el viento por babor, divisamos otro buque de vela por barlovento, que recibe el viento también por babor y se aproxima con riesgo de abordaje. ¿Quién tiene la obligación de maniobrar?","a":["Nosaltres, perquè rebem el vent per babord. / Nosotros, porque recibimos el viento por babor.","L’altre, perquè es troba a sobrevent. / El otro, porque se encuentra a barlovento.","Nosaltres, perquè ens trobem a sotavent. / Nosotros, porque nos encontramos a sotavento.","L’altre, si és un vent del nord. / El otro, si es un viento del norte."],"c":1},{"q":"A i B representen dues embarcacions de propulsió mecànica en una situació d’encreuament amb risc d’abordatge. Quina maniobra, d’acord amb el RIPA, farà l’embarcació A? / A y B representan dos embarcaciones de propulsión mecánica en una situación de cruce con riesgo de abordaje. ¿Qué maniobra, de acuerdo con el RIPA, hará la embarcación A?","a":["Es mantindrà apartada de la derrota de B. / Se mantendrá apartada de la derrota de B.","Mantindrà el seu rumb i la seva velocitat. / Mantendrá su rumbo y su velocidad.","Només maniobrarà quan B sigui un vaixell de vela. / Solo maniobrará cuando B sea un barco de vela.","Emetrà cinc xiulades curtes per cridar l’atenció de B. / Emitirá cinco pitadas cortas para llamar la atención de B."],"c":0},{"q":"A i B representen dues embarcacions de propulsió mecànica en navegació. Com es considera segons el RIPA la situació que apareix en el dibuix? / A y B representan dos embarcaciones de propulsión mecánica en navegación. ¿Cómo se considera según el RIPA la situación que aparece en el dibujo?","a":["De rumbs enfrontats. / De vuelta encontrada.","Embarcació que abasta. / Embarcación que alcanza.","Embarcació que segueix a rumb. / Embarcación que sigue a rumbo.","Situació d’encreuament. / Situación de cruce."],"c":3},{"q":"A i B representen dues embarcacions navegant exclusivament a vela. Qui té l’obligació de maniobrar? / A y B representan dos embarcaciones navegando exclusi - vamente a vela. ¿Quién tiene la obligación de maniobrar?","a":["A, perquè rep el vent per estribord. / A, porque recibe el viento por estribor.","B, perquè rep el vent per babord./ B, porque recibe el viento por babor.","Les dues embarcacions cauran a estribord perquè és una situació de rumb oposat. / Las dos embarcaciones caerán a estribor porque es una situación de vuelta encontrada.","A, perquè es troba a sobrevent. / A, porque se encuentra a barlovento."],"c":1},{"q":"Navegant en un vaixell de propulsió mecànica observem pel nostre babord un vaixell navegant a motor, i com mostra el dibuix, està creuant amb risc d’abordatge sense intenció de maniobrar. Quina maniobra haurem d’efectuar si les circumstàn - cies del cas ho permeten? / Navegando en un buque de propulsión mecánica observa - mos por nuestro babor un buque navegando a motor, y como aparece en el dibujo, está cruzando con riesgo de abordaje sin intención de maniobrar. ¿Qué maniobra deberemos efectuar si las circunstancias del caso lo permiten?","a":["Mantindrem el nostre rumb i la velocitat, ja que tenim preferència. / Mantendremos nuestro rumbo y la velocidad, ya que tenemos preferència.","Canviarem el nostre rumb a estribord per tal d’evitar l’abordatge. / Cambiaremos nuestro rumbo a estribor a fin de evitar el abordaje.","Canviarem el nostre rumb a babord per tal d’evitar l’abordatge. / Cambiaremos nuestro rumbo a babor a fin de evitar el abordaje.","Només maniobrarem si rebem el vent per babord. / Solamente maniobraremos si recibimos el viento por babor."],"c":1},{"q":"Navegant en un vaixell de propulsió mecànica observem per estribord un vaixell navegant a motor que, com apareix en el dibuix, ens acaba de creuar. Quina maniobra haurem d’efectuar? / Navegando en un buque de propulsión mecánica observamos por estribor un buque navegando a motor que, como aparece en el dibujo, nos acaba de cruzar. ¿Qué maniobra deberemos efectuar?","a":["Caurem a estribord. / Caeremos a estribor.","Caurem a babord o a estribord indistintament. / Caeremos a babor o a estribor indistintamente.","Continuarem a rumb. / Continuaremos a rumbo.","El deixarem per la nostra banda de babord. / Lo dejaremos por nuestra banda de babor."],"c":2},{"q":"Quin tipus de vaixell porta hissada una marca bicònica negra (dos cons units per la base)? / ¿Qué tipo de buque lleva izada una marca bicónica negra (dos conos unidos por la base)?","a":["Vaixell remolcador amb la longitud del remolc superior a 200 metres. / Buque remolcador con la longitud del remolque superior a 200 metros.","Veler navegant a vela i motor / Velero navegando a vela y motor","Pesquer d’encerclament amb l’art estès a més de 150 metres del vaixell. / Pesquero de cerco con el arte extendido a más de 150 metros del buque.","Restringit pel seu calat. / Restringido por su calado."],"c":0},{"q":"Un vaixell dedicat a la pesca exhibeix les marques del dibuix. Què significa el con amb el vèrtex cap amunt? / Un buque dedicado a la pesca exhibe las marcas del dibujo. ¿Qué significa el cono con el vértice hacia arriba?","a":["Indica la banda contrària d'aquella on tenen l'ormeig amollat de més de 150 metres. / Indica la banda contraria de aquella en que tienen largado el aparejo de más de 150 metros.","Indica que està navegant a vela i a propulsió mecànica simultàniament./ Indica que está navegando a vela y a propulsión mecánica simultáneamente.","Indica la banda per la qual té l’ormeig, de més de 150 metres, amollat. / Indica a banda por la que tiene el aparejo, de más de 150 metros, largado.","Indica la banda per la qual podem passar. / Indica la banda por la que podemos pasar."],"c":2},{"q":"Per quina banda haurem de passar si en entrar a port ens trobem una draga que exhibeix les marques del dibuix representat? / ¿Por qué banda deberemos pasar si al entrar a puerto nos encontramos una draga que exhibe las marcas del dibujo representado?","a":["Per qualsevol banda. / Por cualquier banda.","Per la de les dues marques bicòniques en línia vertical. / Por la de las dos marcas bicónicas en línea vertical.","Per la de les dues boles. / Por la de las dos bolas.","Les dragues només porten aquest senyal a alta mar. / Las dragas solo llevan esta señal en alta mar."],"c":1},{"q":"Navegant per un canal angost, ¿quin senyal acústic farem a un altre vaixell si el volem avançar per la seva banda d’estribord i només ho podem fer si ell s’aparta per a permetre l’avançament amb seguretat? / Navegando por un canal angosto, ¿qué señal acústica haremos a otro buque si queremos adelantarlo por su banda de estribor y solo podemos hacerlo si él se aparta para permitir el adelantamiento con seguridad?","a":["Dues xiulades llargues seguides d’una curta (– – ·). / Dos pitadas largas seguidas de una corta (– – ·).","Tres xiulades: una curta, una llarga, una curta (· – ·). / Tres pitadas: una corta, una larga, una corta (· – ·).","Dues xiulades llargues seguides de dues curtes (– – · ·). / Dos pitadas largas seguidas de dos cortas (– – · ·).","Cap senyal acústica, ja que si l’altre vaixell ha d’apartar-se, no podem avançar-lo. / Ninguna señal acústica, ya que si el otro buque debe apartarse, no podemos adelantarlo.  UT7 Maniobra / UT7 Maniobra (28-29)"],"c":0},{"q":"Quins caps s’han de reforçar quan estem atracats estribord al moll i ens informen que hi haurà vent de popa? / ¿Qué cabos hay que reforzar si estamos atracados estribor al muelle y nos informan que habrá viento de popa?","a":["Llarg de proa i espring de popa. / Largo de proa y esprín de popa.","Llarg de popa i través de proa. / Largo de popa y través de proa.","Llarg de popa i espring de proa. / Largo de popa y esprín de proa.","Llargs de proa i popa. / Largos de proa y popa."],"c":2},{"q":"Què significa el terme “lascar”? ¿Qué significa el término “lascar”?","a":["Deixar anar una mica un cap que està treballant. / Soltar un poco un cabo que está trabajando.","Tirar d’un cap i anar-lo recollint. / Tirar de un cabo e irlo recogiendo.","Recollir un cap enrotllant-lo sobre ell mateix. / Recoger un cabo enrollándolo sobre sí mismo.","Subjectar un cap mitjançant una bossa. / Sujetar un cabo mediante una boza.  UT8 Emergències a la mar / UT8 Emergencias en la mar (30-32)"],"c":0},{"q":"Què cal tenir en compte quan hem d’utilitzar bengales? ¿Qué deberemos tener en cuenta cuando tengamos que utilizar bengalas?","a":["Disparar-les com més verticalment millor. / Dispararlas lo más vertical posible.","Utilitzar llumins de seguretat. / Utilizar cerillas de seguridad.","Llançar-les per sobrevent. / Lanzarlas por barlovento","Que ens puguin veure. / Que nos puedan ver."],"c":3},{"q":"Una vegada atracats i amb el motor parat, per què prendrem la precaució de tancar l’aixeta de fons? Una vez atracados y con el motor parado, ¿por qué tomaremos la precaución de cerrar la válvula de fondo?","a":["Per a evitar tenir una fuga de combustible. / Para evitar tener una fuga de combustible.","Per a evitar tenir una via d’aigua. / Para evitar tener una vía de agua.","Perquè el motor es refrigeri amb aigua salada. / Para que el motor se refrigere con agua salada.","Perquè el motor es refrigeri únicament amb aigua dolça. / Para que el motor se refrigere únicamente con agua dulce."],"c":1},{"q":"Quan s’ha d’abandonar el vaixell? ¿Cuándo se debe abandonar el buque?","a":["Després de comprovar que cap tripulant ha sofert danys. / Después de comprobar que ningún tripulante ha sufrido daños.","Quan aquest ofereixi menys garantia de protecció que qualsevol altre mitjà de supervivència. / Cuando este ofrezca menos garantia de protección que cualquier otro medio de supervivencia.","Després d’haver embarrancat. / Después de haber embarrancado.","Quan hàgim comprovat que és impossible arrencar el motor. / Cuando hayamos comprobado que es imposible arrancar e motor."],"c":1},{"q":"En quin sentit gira el vent en una zona de baixa pressió o borrasca a l’hemisferi nord? / ¿En qué sentido gira el viento en una zona de baja presión o borrasca en el hemisferio norte?","a":["De nord a sud. / De norte a sur.","En sentit antihorari. / En sentido antihorario.","De sud a nord. / De sur a norte.","En sentit horari. / En sentido horario."],"c":1},{"q":"Què interpretem quan en un mapa meteorològic observem les isòbares molt juntes? ¿Qué interpretamos cuando en un mapa meteorológico observamos las isóbaras muy juntas?","a":["Que en aquesta zona hi ha un vent fort. / Que en esa zona hay un viento fuerte.","Que pujarà la temperatura. / Que la temperatura subirá.","Que el temps millorarà. / Que el tiempo mejorará.","Que el vent caurà. / Que el viento caerá."],"c":0},{"q":"De quines tres variables depèn l’altura de les onades? ¿De qué tres variables depende la altura de las olas?","a":["Intensitat, resistència i fetch. / Intensidad, resistencia y fetch.","Velocitat, resistència i fetch. / Velocidad, resistencia y fetch.","Intensitat, persistència i fetch. / Intensidad, persistencia y fetch.","Intensitat, velocitat i fetch. / Intensidad, velocidad y fetch."],"c":2},{"q":"Si estem fondejats i l’indicador de l’anemòmetre marca 15, vol dir que: Si estamos fondeados y el indicador del anemómetro marca 15, quiere decir que:","a":["El vent és del N15E / El viento es del N15E.","El vent té una direcció igual a 015º / El viento tiene una dirección igual a 015º.","El vent aparent té una velocitat de 1,5 nusos / El viento aparente tiene una velocidad de 1,5 nudos.","El vent real té una velocitat de 15 nusos / El viento real tiene una velocidad de 15 nudos."],"c":3},{"q":"Què és la latitud? ¿Qué es la latitud?","a":["L’arc d’equador comprès entre el meridià de Greenwich i el meridià del lloc. / El arco de ecuador comprendido entre el meridiano de Greenwich y el meridiano del lugar.","L’arc de paral·lel comprès entre el meridià de Greenwich i el meridià del lloc. / El arco de paralelo comprendido entre el meridiano de Greenwich y el meridiano del lugar.","L’arc de meridià comprès entre el pol i el lloc. / El arco de meridiano comprendido entre el polo y el lugar.","L’arc de meridià comprès entre l’equador i el lloc. / El arco de meridiano comprendido entre el ecuador y el lugar."],"c":3},{"q":"Com s’anomena el meridià a partir del qual es mesuren les longituds? ¿Cómo se denomina el meridiano a partir del cual se miden las longitudes?","a":["Meridià del lloc. / Meridiano del lugar.","Meridià 180º. / Meridiano 180º.","Meridià de Greenwich. / Meridiano de Greenwich.","Meridià equatorial. / Meridiano ecuatorial."],"c":2},{"q":"Què representa el símbol de la imatge, utilitzat en les cartes nàutiques? ¿Qué representa el símbolo de la imagen, utilizado en las cartas náuticas?","a":["Reserva marina. / Reserva marina.","Ancoratge prohibit. / Fondeadero prohibido.","Cable submarí. / Cable submarino.","Àrea d’ancoratge. / Área de fondeo."],"c":1},{"q":"Quin és el significat de (9M) en les característiques del següent far: Gp Oc (2) 6s 11m 9M? ¿Cuál es el significado de (9M) en las características del siguiente faro: Gp Oc (2) 6s 11m 9M?","a":["Elevació del far: 9 milles. / Elevación del faro: 9 millas.","Elevació del far sobre el nivell mig del mar: 9 metres. / Elevación del faro sobre el nivel medio del mar: 9 metros.","Abast lumínic del far: 9 milles. / Alcance lumínico del faro: 9 millas.","Distància del far a la mar: 9 milles. / Distancia del faro a la mar: 9 millas."],"c":2},{"q":"Quina és la demora vertadera (Dv) del far del cap de Tortosa si navegant al rumb vertader (Rv) = 000º observem el far pel través de babord? ¿Cuál es la demora verdadera (Dv) del faro del cabo de Tortosa si navegando al rumbo verdadero (Rv) = 000º observamos el faro por el través de babor?","a":["090º.","180º.","270º.","000º."],"c":2},{"q":"Quina serà la nostra situació si, navegant al rumb vertader (Rv) = 047º, prenem marcació del far de PUNTA EUROPA (M) = 090º babord i la distància a aquest far és de 5,6 milles? ¿Cuál será nuestra situación si, navegando al rumbo verdadero (Rv) = 047º, tomamos marcación del faro de PUNTA EUROPA (M) = 090º babor y la distancia a este faro es de 5,6 millas?","a":["l = 36º 02,8’ N – L = 005º 25,6 W","l = 36º 02,5’ N – L = 005º 15,8 W","l = 36º 10,8’ N – L = 005º 15,8 W","l = 36º 01,9’ N – L = 005º 15,2 W"],"c":1},{"q":"Estem navegant per la zona de l’Estret de Gibraltar, a velocitat de maquines 10 nusos i amb un rumb d’agulla (Ra) = 092º. A HRB = 13:00 ens trobem en la situació l = 36º 00,0’ N i L = 005º 30,0’ W. Seguim navegant al mateix rumb i velocitat fins a HRB = 14:15 on decidim que volem dinar. En quina situació ens trobarem en el moment que hem decidit dinar si tenim una declinació magnètica = 3º(E) i un desviament= 5º(-)? / Estamos navegando por la zona del Estrecho de Gibraltar, a velocidad de máquinas 10 nudos con un rumbo de aguja (Ra)= 092º. A HRB = 13:00 nos encontramos en la situación l = 36º 00,0’ N i L = 005º 30,0’ W. Seguimos navegando al mismo rumbo y velocidad hasta HRB = 14:15 donde decidimos que queremos almorzar. ¿En qué situación nos encontraremos en el momento que hemos decidido almorzar si tenemos una declinación magnètica = 3º (E) y un desvío= 5º(-)?","a":["l = 36º 00,0’ N – L = 005º 14,6’ W","l = 36º 00,0’ N – L = 005º 21,0' E","l = 36º 00,0’ N – L = 005º 20,8' W","l = 36º 00,0’ N – L = 005º 14,5' E"],"c":0},{"q":"Quina és la isòbata que passa per un punt de la carta situat a l = 35º 54,6' N i L = 005º 58,4' W? ¿Cuál es la isobata que pasa por un punto de la carta situado en l = 35º 54,6' N y L = 005º 58,4’ W?","a":["75 m","50 m","56 m","100 m"],"c":3},{"q":"Quina situació obtindrem (latitud – Longitud) si prenem simultàniament demo - ra vertadera del far de CAP TRAFALGAR (Dv) = 107º i demora vertadera del far de CAP ROCHE (Dv) = 006º? ¿Qué situación obtendremos (latitud – Longitud) si tomamos simultáneamente demora verdadera del faro de CABO TRAFALGAR (Dv) = 107º y demora verdadera del faro de CABO ROCHE (Dv) = 006º?","a":["l = 36º 14,8’ N – L = 006º 09,8’ W","l = 36º 12,4’ N – L = 006º 07,7’ W","l = 36º 12,8’ N – L = 006º 11,0’ W","l = 36º 12,8’ N – L = 006º 09,0’ W"],"c":3}]},{"name":"PEE Mayo 1","code":"GI0526PEE-1","date":"23/05/2026","questions":[{"q":"Com s’anomena l’element estructural que prolonga la quilla per la part on termina la popa? / ¿Cómo se llama el elemento estructural que prolonga la quilla por la parte donde termina la popa?","a":["Trancanell. / Trancanil.","Orsa. / Orza.","Roda. / Roda.","Codast. / Codaste."],"c":3},{"q":"Quin assentament tenim, expressat en metres, si el nostre calat a proa és de 1,5 metres i el de popa és de 1,8 metres? / ¿Qué asiento tenemos, e x p r e s a d o en metros, si nuestro calado a proa es de 1,5 metros y el de popa es de 1,8 metros?","a":["0,80 empopant. /0,80 apopante.","0,30 emproant. / 0,30 aproante.","0,30 empopant. / 0,30 apopante.","0,45 empopant. / 0,45 apopante."],"c":2},{"q":"Per a què serveix el grillet d’unió? / ¿Para qué sirve el grillete de unión?","a":["Per evitar el garreix de l’ancora / Para evitar el garreo del ancla","Per assegurar la cadena de l’ancora./ Para asegurar la cadena del ancla.","Per repartir els esforços entre els eslavons de la cadena./ Para repartir los esfuerzos entre los eslabones de la cadena.","Per evitar que el gir de l’ancora provoqui torsions en els eslavons de la cadena./ Para evitar que el giro del ancla provoque torsiones en los eslabones de la cadena."],"c":3},{"q":"Com s’anomena la semisuma dels valors dels calats de proa i popa? / ¿Cómo se denomina la semisuma de los valores de los calados de proa i popa?","a":["Assentament / Asiento.","Calat de flotació / Calado de flotación.","Calat mitja / Calado medio.","Puntal. / Puntal"],"c":2},{"q":"Quina funció principal té l’orinc? / ¿Qué función principal tiene el orinque?.","a":["Mantenir l’embarcació dreçada. / Mantener la embarcación adrizada.","Abalisar l´àncora mitjançant el gaiatell. / Balizar el ancla mediante el boyarín.","Senyalitzar la posició del vaixell. / Señalizar la posición de la embarcación.","Ajudar en la maniobra d’atracament. / Ayudar en la maniobra de atraque."],"c":1},{"q":"Quin dels següents nusos es pot utilitzar per fer una gassa? / ¿Cuál de los siguientes nudos se puede utilizar para hacer una gaza?","a":["Nus de pardal. / Ballestrinque.","Pla. / Llano.","As de guia./ As de guía.","Volta de ruixó. / Vuelta de rezón."],"c":2},{"q":"Què és l’evolució o corba de Boutakow representada en el dibuix? / ¿Qué es la evolución o curva de Boutakow representada en el dibujo?","a":["És una maniobra que s’utilitza per a mantenir el rumb quan s’està capejant un temporal. / Es una maniobra que se utiliza para mantener el rumbo cuando se está capeando un temporal.","És una maniobra de recerca emprada quan no es veu el nàufrag. / Es una maniobra de búsqueda empleada cuando no se ve al náufrago.","És una maniobra que serveix per a aproximar-nos a un nàufrag quan aquest està a la vista. / Es una maniobra que sirve para aproximarnos a un náufrago cuando este está a la vista.","És una maniobra emprada per a aproximar-nos al moll a l’hora d’atracar. / Es una maniobra empleada para aproximarnos al muelle en el momento de atracar."],"c":2},{"q":"Quines accions inicials calen fer en el cas d’home a l’aigua ? / ¿Qué acciones iniciales hemos de realizar en caso de hombre al agua?","a":["Cridar “Home a l’aigua”, posar el timó a la banda contraria de caiguda del nàufrag, llençar un cèrcol salvavides i no perdre´l de vista. / Gritar “Hombre al agua”, poner el timón a la banda contraria de caída del náufrago, lanzar un aro salvavidas y no perderlo de vista.","Cridar “Home a l’aigua”, posar el timó a la banda de caiguda del nàufrag, llençar un cèrcol salvavides i no perdre´l de vista. / Gritar “Hombre al agua”, poner el timón a la banda de caída del náufrago, lanzar un aro salvavidas y no perderlo de vista.","Cridar “Home a l’aigua” i posar el timó a la via. / Gritar “Hombre al agua” y poner el timón a la vía.","Aturar l’embarcació i fer enrere./ Detener la embarcación y dar atrás."],"c":1},{"q":"Què significa posar el vaixell \"a la colla\"? / ¿Qué significa poner el barco “a son de mar”?","a":["Desactivar l’alliberador hidrostàtic del bot inflable salvavides per a evitar que un cop de mar l’accioni. / Desactivar la zafa hidrostática de la balsa salvavidas hinchable para evitar que un golpe de mar la accione.","Desamarrar el vaixell completament del moll. / Desamarrar el barco completamente del muelle.","Deixar totes les escotilles obertes perquè es ventilin els espais interiors. / Dejar todas las escotillas abiertas para que se ventilen los espacios interiores.","Tenir cada cosa al seu lloc, estibada i trincada. / Tener cada cosa en su sitio, estibada y trincada."],"c":3},{"q":"Quina maniobra de recerca és la més adequada quan no es veu el/la nàufrag/a? / ¿Qué maniobra de búsqueda es la más adecuada cuando no se ve al/la náufrago/a?","a":["Exploració en espiral quadrada / Exploración en espiral cuadrada","Maniobra de Boutakow. / Maniobra de Boutakow.","Exploració circular. / Exploración circular.","Maniobra d’Anderson. / Maniobra de Anderson."],"c":0},{"q":"A partir de quina distància de la costa es poden llençar restes de menjar sense triturar a la mar fora de les zones especials? / ¿A partir de qué distancia de la costa se pueden tirar restos de comida sin triturar a la mar fuera de las zonas especiales?","a":["A partir de 3 milles. / A partir de 3 millas.","A partir de 12 milles. / A partir de 12 millas.","A qualsevol distància de la costa perquè són residus orgànics. / Se pueden tirar a cualquier distancia de la costa porque son residuos orgánicos.","No es poden llençar a cap distància. / No se pueden tirar a ninguna distancia."],"c":1},{"q":"A l’entrada i sortida de port, qui té la preferència de pas? / En la entrada y salida de puerto, ¿quién tiene preferencia de paso?","a":["Les embarcacions que entren a la bocana. / Las embarcaciones que entran a la bocana.","Les embarcacions que entren a la bocana per estribord. / Las embarcaciones que entran a la bocana por estribor","Les embarcacions que surten a la bocana. / Las embarcaciones que salen a la bocana.","Les embarcacions que entren a la bocana per babord./ Las embarcaciones que entran a la bocana por babor."],"c":2},{"q":"De quin color és el llum que emet una marca lateral de estribor a la Regió A?/. ¿De qué color es la luz que emite una marca lateral de Estribor en la Región A?","a":["Groc / Amarilla","Blanc / Blanca","Vermell / Roja","Verd. / Verde"],"c":3},{"q":"Quina marca de cap de color negre del sistema cardinal ens indica “aigües navegables al quadrant Est” ? / ¿Qué marca de tope de color negro del sistema cardinal nos indica “aguas navegables en el cuadrante Este”?","a":["Dos cons amb els vèrtexs cap avall. / Dos conos con los vértices hacia abajo.","Dos cons amb els vèrtexs oposats. / Dos conos con los vértices opuestos.","Dos cons amb els vèrtexs cap amunt. / Dos conos con los vértices hacia arriba.","Dos cons oposats per les seves bases. / Dos conos opuestos por sus bases."],"c":3},{"q":"- Com reconeixem un tipus de llum isofase (Iso)? / ¿Cómo reconocemos un tipo de luz isofase (Iso)?","a":["Perquè emet llum de forma continuada. / Porqué emite luz de forma continua.","Perquè emet llampades segons el codi Morse / Porqué emite destellos según el código Morse.","Perquè emet en períodes iguals de llum i de foscor / Porqué emite en periodos iguales de luz y oscuridad.","Perquè emet llampades ràpides, entre 50 i 300 per minut / Porqué emite destellos rápidos, entre 50 y 300 por minuto"],"c":2},{"q":"- Què ens indica un llum blanc q ue ens trobem a la mar fent sis centellejos més una llampada llarga cada quinze segons? / ¿Qué nos indica una luz blanca que nos encontramos en la mar haciendo seis centelleos más un destello largo cada quince segundos?","a":["El quadrant oest d’un perill és el navegable. / El cuadrante oeste de un peligro es el navegable.","El quadrant sud d’un perill és el navegable. / El cuadrante sur de un peligro es el navegable.","Aigües navegables per estribord del llum. / Aguas navegables por estribor de la luz.","Aigües navegables per babord del llum. / Aguas navegables por babor de la luz."],"c":1},{"q":"Quin tipus de marca és la que la seva característica diürna més important és que la seva marca de topall són dues boles negres superposades? ¿Qué tipo de marca es la que su característica diurna más importante es que su marca de tope son dos bolas negras superpuestas?","a":["Marca lateral. / Marca lateral.","Marca de perill aïllat. / Marca de peligro aislado.","Marca especial. / Marca especial.","Marca cardinal. / Marca cardinal."],"c":1},{"q":"Quin tipus de vigilància hem d’efectuar quan estem fondejats amb boira, segons el RIPA? / ¿Qué tipo de vigilancia debemos de efectuar cuando estamos fondeados con niebla, según el RIPA?","a":["Només farem atenció de la pantalla del radar. / Solo prestaremos atención a la pantalla del radar.","Només auditiva. / Solo auditiva.","Visual i auditiva. / Visual y auditiva.","No fa falta efectuar cap tipus de vigilància quan estem fondejats. / No hace falta efectuar ningún tipo de vigilancia cuando estamos fondeados"],"c":2},{"q":"Segons el RIPA, qui pot quedar exempt de les conseqüències d’una negligència? / Según el RIPA, ¿quién puede quedar exento de las consecuencias de una negligencia?","a":["El capità, si compleix parcialment el reglament. / El capitán, si cumple parcialmente el reglamento.","El propietari del buc, però no la tripulació. / El propietario del buque, pero no la tripulación.","Ningú queda exempt per negligència en el compliment del reglament o de la pràctica marinera. / Nadie queda exento por negligencia en el cumplimiento del reglamento o de la práctica marinera.","Només queda exempt el buc que navega amb poca visibilitat. / Solo queda exento el buque que navega con poca visibilidad."],"c":2},{"q":"En una situació de volta trobada entre dos bucs de propulsió mecànica amb risc d’abordatge, què farà cada buc? / En una situación de vuelta encontrada entre dos buques de propulsión mecánica con riesgo de abordaje, ¿qué hará cada buque?","a":["Mantindrà rumb i velocitat sempre, no es considera una situació de risc segons el RIPA. / Mantendrá rumbo y velocidad siempre, no se considera una situación de riesgo segun el RIPA.","Caurà a estribord per passar per la banda de babord de l’altre. / Caerá a estribor para pasar por la banda de babor del otro.","Caurà a babord per passar per la banda de estribord de l’altre. / Caerá a babor para pasar por la banda de estribor del otro.","El primer vaixell que detecta el risc maniobrarà a babord o estribord indistintament. / El primer buque que detecte el riesgo maniobrará a babor o estribor indistintamente."],"c":1},{"q":"A i B representen dues embarcacions de propulsió mecànica en una situació d’encreuament amb risc d’abordatge. Quina maniobra, d’acord amb el RIPA, farà l’embarcació A? / A y B representan dos embarcaciones de propulsión mecánica en una situación de cruce con riesgo de abordaje. ¿Qué maniobra, de acuerdo con el RIPA, hará la embarcación A?","a":["Mantindrà el seu rumb i la seva velocitat. / Mantendrá su rumbo y su velocidad.","Només maniobrarà quan B sigui un vaixell de vela. / Solo maniobrarà cuando B sea un barco de vela.","Emetrà cinc xiulades curtes per cridar l’atenció de B./ Emitirá cinco pitadas cortas para llamar la atención de B.","Es mantindrà apartada de la derrota de B. / Se mantindrà apartada de la derrota de B."],"c":3},{"q":"“A” representa un vaixell dedicat a la pesca i “B” un vaixell de vela. Quin haurà de maniobrar, d’acord amb el RIPA, en la situació que apareix en el dibuix? / “A” representa un buque dedicado a la pesca y “B” un buque de vela. ¿Quién deberá maniobrar, de acuerdo con el RIPA, en la situación que se muestra en el dibujo?","a":["El vaixell dedicat a la pesca. / El buque dedicado a la pesca.","El vaixell de vela. / El buque de vela.","Ambdós vaixells canviaran el rumb. / Ambos buques cambiarán el rumbo.","El vaixell de propulsió mecànica. / El buque de propulsión mecánica."],"c":1},{"q":"Navegant en un vaixell de vela se’ns apropa pel costat de babord, amb risc d’abordatge (situació d’encreuament), un vaixell remolcant que exhibeix les marques del dibuix. Qui haurà de maniobrar? / Navegando en un buque de vela se nos acerca por el costado de babor, con riesgo de abordaje (situación de cruce), un buque remolcando que exhibe las marcas del dibujo. ¿Quién deberá maniobrar?","a":["Nosaltres, ja que l’altre és un remolcador. / Nosotros, ya que el otro es un remolcador.","Nosaltres, perquè l’altre té la capacitat de maniobra restringida. / Nosotros, porque el otro tiene la capacidad de maniobra restringida.","Nosaltres, ja que la longitud del remolc és superior a 200 m. / Nosotros, ya que la longitud del remolque es superior a 200 m.","El vaixell que remolca, perquè ens creua per babord. / El buque que remolca, porque nos cruza por babor."],"c":2},{"q":"Què ens indica un vaixell que porta hissada, a la part de proa, la marca que es mostra en el dibuix? ¿Qué nos indica un buque que lleva izada, en la parte de proa, la marca que se muestra en el dibujo?","a":["Que és un vaixell sense govern i sense arrencada. / Que es un buque sin gobierno y sin arrancada.","Que és una embarcació embarrancada d’eslora inferior a 12 metres. / Que es una embarcación varada de eslora inferior a 12 metros.","Que és un vaixell fondejat. / Que es un buque fondeado.","Que és un vaixell amb pràctic a bord. / Que es un buque con práctico bordo."],"c":0},{"q":"Quin tipus de vaixell porta hissada la marca del dibuix? / ¿Qué tipo de buque lleva izada la marca del dibujo?","a":["El dedicat a la pesca. / El dedicado a la pesca.","Amb capacitat de maniobra restringida. / Con capacidad de maniobra restringida.","El restringit pel seu calat. / El restringido por su calado.","El remolcador amb longitud de remolc superior a 200 metres / El remolcador con longitud de remolque superior a 200 metros."],"c":1},{"q":"Quin tipus d’embarcació exhibeix els següents llums? / ¿Qué tipo de embarcación exhibe las siguientes luces?","a":["Vaixell dedicat a la pesca vist pel seu costat de babord. / Buque dedicado a la pesca visto por su costado de babor.","Vaixell de vela vist pel seu costat de babord. / Buque de vela visto por su costado de babor.","Vaixell remolcat amb longitud del remolc superior a 20 metres. / Buque remolcado con longitud del remolque superior a 20 metros.","Vaixell d’arrossegament vist pel seu costat de babord. / Buque de arrastre visto por su costado de babor."],"c":1},{"q":"Què ens està indicant un vaix ell mercant quan a l’interior d ’un port emet tres xiulades curtes? (●●●) / ¿Qué nos està indicando un buque mercante cuando en el interior de un puerto emite tres pitadas cortas? (●●●)","a":["Que està fent enrere. / Que está dando atrás.","Que cau a estribord. / Que cae a estribor.","Que està fent avant. / Que está dando avante.","Que cau a babord. / Que cae a babor."],"c":0},{"q":"Com s’anomena la maniobra que consisteix en atracar un vaixell al costat de l’altre? / ¿Cómo se denomina la maniobra consistente en atracar un barco al costado de otro?","a":["Defensar-se. / Defenderse.","Fondejar. / Fondear.","Abarloar. / Abarloar.","Ciavogar. / Ciabogar."],"c":2},{"q":"Una embarcació, parada i sense arrencada, disposa d’una hèlice que gira a l’esquerra en màquina enrere. Cap a quina banda caurà la popa si donem enrere en una maniobra amb el tim a la via? / Una embarcación, parada y sin arrancada, dispone de una hélice que gira a la izqui erda en ma quina atrás. ¿Hacia qué banda caerá la popa si damos atrás en una maniobra con el timón a la vía?","a":["A babord. / A babor.","A estribord. / A estribor.","El gir de l’hèlice no provoca cap efecte. / El giro de la hélice no provoca ningún efecto.","Al posar el timó al mig, no caurà cap a cap banda. / Al poner el timón a la vía, no caerá hacia ninguna banda."],"c":0},{"q":"Quines característiques tenen les hemorràgies venoses quant al color de la sang i la forma de sagnar? / ¿Qué características tienen las hemorragias venosas respecto al color de la sangre y la forma de sangrar?","a":["Vermell fosc i a batzegades. / Rojo oscuro y a golpes.","Vermell viu i de forma contínua. / Rojo vivo y de forma continua.","Vermell viu i a batzegades. / Rojo vivo y a golpes.","Vermell fosc i de forma contínua. / Rojo oscuro y de forma continua."],"c":3},{"q":"Quina classe d’incendi es produeix si es bota foc a l’oli vegetal d’una paella? / ¿Qué clase de incendio se produce si se prende fuego al aceite vegetal de una sartén?","a":["Classe A. / Clase A.","Classe B. / Clase B.","Classe C. / Clase C.","Classe F. / Clase F."],"c":3},{"q":"Com s’anomena el forat per on l’eix de l’hèlice travessa el buc, que és un dels punts de major risc per on podem tenir una via d’aigua? ¿Cómo se denomina el orificio por donde el eje de la hélice atraviesa el casco, que es uno de los puntos de mayor riesgo por donde podemos tener una vía de agua?","a":["Embornal. / Imbornal.","Gatera. / Gatera.","Botzina. / Bocina.","Llimera. / Limera."],"c":2},{"q":"Quina de les següents expressions NO és correcte? / ¿Cuál de las siguientes expresiones NO es correcta?","a":["Una borrasca està associada amb mal temps per navegar / Una borrasca está asociada con mal tiempo para navegar","Un anticicló porta bons temps per navegar / Un anticiclón trae buen tiempo para navegar.","Un anticicló és una àrea d’altes pressions / Un anticiclón es una área de altas presiones","Un anticicló és signe de mal temps / Un anticiclón es signo de mal tiempo"],"c":3},{"q":"– Estem navegant a la Mediterrània i sobtadament observem que les lectures del baròmetre indiquen una baixada brusca de la pressió atmosfèrica i el termòmetre indica baixada de temperatura, què està passant meteorològicament? / Estamos navegando en el Mediterráneo y repentinamente observamos que las lecturas del barómetro indican una bajada brusca de la presión atmosférica y el termómetro indica bajada de la temperatura ¿qué está sucediendo meteorológicamente?","a":["El temps està millorant / El tiempo está mejorando","Està venint pols saharià amb vent del sud / Está viniendo polvo sahariano con viento del sur","S’acosta un anticicló / Se acerca un anticiclón","El vent està refrescant i el temps empitjora / El viento está refrescando y el tiempo empeora."],"c":3},{"q":"Amb quines unitats es mesura el fetch? / ¿En qué unidades se mide el fetch?","a":["Km². / km².","Milles. / Millas.","Hores. / Horas.","Nusos. / Nudos."],"c":1},{"q":"Normalment en quin sentit es desplacen les àrees de baixes pressions a l’hemisferi nord ? / ¿Normalmente en qué sentido se desplazan las áreas de bajas presiones en el hemisferio norte?","a":["D’Oest a Est./ De Oeste a Este.","De Sud a Nord / De Sur a Norte.","D’Est a Oest./ De Este a Oeste.","De Nord a Sud / De Norte a Sur"],"c":0},{"q":"Com s’anomena el meridià a partir del qual es mesuren les longituds? / ¿Cómo se denomina el meridiano a partir del cual se miden las longitudes?","a":["Tròpic. / Trópico.","Equador. / Ecuador.","Greenwich. / Greenwich.","Meridià de Sandvitx. / Meridiano de Sanwich."],"c":2},{"q":"Com s’anomena l’angle que forma la direcció de l’agulla nàutica amb el nord verdader? / ¿Cómo se denomina el ángulo que forma la dirección de la aguja náutica con el norte verdadero?","a":["Variació local / Variación local","Declinació magnètica. / Declinación magnética.","Correcció total / Corrección total.","Desviament. / Desvío."],"c":2},{"q":"Quina declinació magnètica tindrem a un lloc per l’any 2026, si la declinació magnètica per l’any 2016 era 3º 05’ W i la variació anual és 6’E? / ¿Qué declinación magnética tendremos en un lugar, para el año 2026 si la declinación magnética para el año 2016 era 3º 05’ W y la variación anual es 6’E?","a":["1º 05’W","1º55’W","60’E","2º 05’ W"],"c":3},{"q":"Què significa la llegenda que figura a la carta per a definir el far de Punta Carnero “Fl(4)WR.20s16/13M”? / ¿Qué significa la leyenda que figura en la carta para definir el faro de Punta Carnero “Fl(4)WR.20s16/13M”?","a":["La torre del far és del segle 20. Està construït sobre un turó amb una alçada total de 16 metres sobre el nivell del mar. El seu indicatiu de radio és wisqui - romeo. / La torre del faro es del siglo 20. Está construido sobre un montículo con una altura total de 16 metros sobre el nivel del mar. Su indicativo radio es wisqui – romeo.","És la llegenda característica que tenen igual tots els fars al Mediterrani i que serveixen per a guiar als vaixells en condicions de poca visibilitat . / Es la leyenda que tienen igual todos los faros del Mediterráneo i que sirve para guiar a los barcos en condiciones de poca visibilidad.","Abast lumínic de entre 13 i 16 milles nàutiques de llum blanca / Alcance lumínico de entre 13 i 16 millas náuticas de luz blanca.","El far té dos llums, un blanc i l’altre roig, emet grups de 4 flaixos cada 20 segons. El llum blanc té un abast visu al de 16 milles nàutiques i el llum roig de 13 milles nàutiques. / El faro tiene dos luces , una blanca y la otra roja, emite grupos de 4 flashes cada 20 segundos. La luz blanca tiene un alcance visual de 16 millas náuticas y la luz roja de 13 millas náuticas."],"c":3},{"q":"Què representa el símbol del dibuix que s’utilitza sovint a la carta nàutica? / ¿qué representa el símbolo del dibujo que se utiliza a menudo en la carta náutica?","a":["Velocitat màxima 29 nusos / Velocidad máxima 29 nudos","Sonda 29 metres. Fons de pedra. / Sonda 29 metros. Fondo de piedra","Sonda 29 metres. Fons sorrenc. / Sonda 29 metros. Fondo arenoso","Prohibit el fondeig / Prohibido el fondeo"],"c":1},{"q":"Després d’haver passat uns dies a Girona fruint del “Temps de Flors” ens embarquem a bord d’un veler i naveguem fins a la zona de l’Estret de Gibraltar. El dia 23 de maig de 2026, a HRB=10:45, estem navegant al rumb verdader, Rv=95º.En aquest moment volem situar-nos i prenem simultàniament: marcació del far de Cap Roche, M=77ºbabord i marcació del far de Cap Trafalfar, M=23ºbabord. On som a HRB=10:45? Después de haber pasado unos días en Girona disfrutando del “Temps de Flors” nos embarcamos a bordo de un velero y navegamos hasta la zona del Estrecho de Gibraltar. El día 23 de mayo de 2026, a HRB=10:45, estamos navegando al rumbo verdadero, RV=95º. En este momento nos queremos situar y tomamos simultáneamente: marcación del faro de Cabo Roche, M=77ºbabor, y marcación del faro de Cabo Trafalgar, M=23ºbabor. ¿Dónde estamos a HRB=10:45?","a":["l= 36º 08,2’N – L=006º 12,0’W","l= 36º 09,8’N – L=006º 11,0’W","l= 36º 11,2’N – L=006º 10,0’W","l= 36º 09,8’N – L=006º 10,0W"],"c":0},{"q":"Estem situats a la demora verdadera del far de Punta Carnero, Dv= 283º i a una distància del mateix de 3,2 milles nàutiques. Tenim una correcció total, CT= -2º i volem anar fins el llum vermell del port d’Algecires “Fl(2)R6s8M”. A quin rumb d’agulla, Ra, haurem de navegar? Estamos situados en la demora verdadera del faro de Punta Carnero, Dv= 283º y a una distancia del mismo de 3,2 millas náuticas. Tenemos una corrección total, CT= -2º y queremos ir hasta la luz roja del puerto de Algeciras “Fl(2)R6s8M”. ¿A qué rumbo de aguja deberemos navegar?","a":["Ra= 329º","Ra= 322º","Ra= 337º","Ra= 315º"],"c":0},{"q":"El dia 23 de maig de 2026, a HRB 10:15, estem a l’oposició dels fars de Cabo Trafalgar i Punta Malabata i simultàniament prenem demora d’agulla de Cabo Trafalgar (Da) = 331º. Quina correcció total (Ct) tenim al rumb que naveguem? / El día 23 de mayo de 2026, a HRB 10:15, estamos en la oposición de los faros de Cabo Trafalgar y Punta Malabata y simultáneamente tomamos demora de aguja de Cabo Trafalgar (Da) = 331º. ¿Qué corrección total (Ct) tenemos al rumbo que navegamos?","a":["Ct = (–3º)","Ct = (–5,5º)","Ct = (2º)","Ct = (+3,5º)"],"c":0},{"q":"Demà, 24 de maig de 2026 salparem del port d’Algecires amb la segona plenamar des d’un punt on hi ha sonda carta de 3 metres. Si tenim una pressió atmosfèrica de 963 mil·libars, quina sonda moment (Sm) tindrem? / Mañana, 24 de mayo de 2026 zarparemos del puerto de Algeciras con la segunda pleamar desde un punto donde hay una sonda carta de 3 metros. Si tenemos una presión atmosférica de 963 milibares. ¿Qué sonda momento (Sm), tendremos?","a":["Sm= 3,49m","Sm= 5,29m","Sm= 3,19m","Sm= 4,49m"],"c":3}]},{"name":"PEE Mayo 2","code":"GI0526PEE-2","date":"23/05/2026","questions":[{"q":"Com s’anomena l’acció de cobrar la cadena de l’àncora amb el molinet? / ¿Cómo se denomina la acción de cobrar la cadena del ancla con el molinete?","a":["Llevar. / Zarpar.","Filar. / Filar.","Afermar. / Afirmar.","Virar. / Virar."],"c":3},{"q":"Quin assentament tenim, expressat en metres, si el nostre calat a proa és de 1,5 metres i el de popa és de 1,9 metres? / ¿Qué asiento tenemos, e x p r e s a d o en metros, si nuestro calado a proa es de 1,5 metros y el de popa es de 1,9 metros?","a":["0,80 empopant. /0,80 apopante.","0,40 emproant. / 0,40 aproante.","0,40 empopant. / 0,40 apopante.","0,45 empopant. / 0,45 apopante."],"c":2},{"q":"Per a què serveix l’embragament del molinet? / ¿Para qué sirve el embrague del molinete?","a":["Per a bloquejar el barbotí./ Para bloquear el barbotén.","Per acoblar o desacoblar el barbotí a l’eix motor ./ Para acoplar o desacoplar el barbotén al eje motor.","Per evitar la pèrdua de l’ancora./ Para evitar la pérdida del ancla.","Per frenar l’ancora en la maniobra de fondeig ./ Para frenar el ancla en la maniobra de fondeo."],"c":1},{"q":"Com s’anomena el forat per on discorre la metxa del timó? / ¿Cómo se llama el orificio por el que discurre la mecha del timón?","a":["Embornal. / Imbornal.","Gater. / Gatera.","Timonera. / Timonera.","Llimera. / Limera."],"c":3},{"q":"Per a què serveixen el coll de cigne situat a coberta I que es mostra en la figura? / ¿Para qué sirve el manguerote situado en cubierta y que se muestra en la figura?","a":["Per a permetre la ventilació dels compartiments interiors. / Para permitir la ventilación de los compartimentos interiores.","Per a permetre l’entrada de llum. / Para permitir la entrada de luz.","Per a il·luminar les cabines. / Para iluminar los camarotes.","Per a impedir l’entrada d’aire i la sortida d’aigua. / Para impedir la entrada de aire y la salida de agua."],"c":0},{"q":"Què haurem de fer per saber on queda fondejada l’àncora ? / ¿Qué deberemos hacer para saber dónde queda fondeada el ancla?","a":["Orincar-la / Orincarla","Arrelar-la. / Arraigarla.","Mesurar la fondària. / Medir la sonda.","Contar les baules. / Contar los eslabones."],"c":0},{"q":"Quina maniobra seria la més adient per reduir balanços en un vaixell? / ¿Qué maniobra será la más adecuada para reducir balances en un barco?","a":["Augmentar la velocitat. / Aumentar la velocidad.","Modificar el rumb. / Modificar el rumbo.","Traslladar pesos a una banda. / Trasladar pesos a una banda.","Llençar pesos per la borda. / Lanzar pesos por la borda."],"c":1},{"q":"Per què hem d’extremar les precaucions quan naveguem per aigües somes? / ¿Por qué debemos extremar las precauciones cuando navegamos por aguas someras?","a":["Perquè hi ha molt poca visibilitat del fons. / Porque hay muy poca visibilidad del fondo.","Perquè hi ha una alta densitat de trànsit. / Porque hay una alta densidad de tráfico.","Perquè hi ha corrents forts. / Porque hay fuertes corrientes.","Perquè hi ha risc d’embarrancar. / Porque existe el peligro de embarrancar."],"c":3},{"q":"Com s’anomena el dispositiu que permet l’alliberament automàtic del rai salvavides en cas d’enfonsament de l’embarcació? / ¿Cómo se llama el mecanismo que permite la liberación automática de la balsa salvavidas en caso de hundimiento de la embarcación?","a":["Cap d’amarrament./ Cabo de amarre","Cap disparador./ Cabo disparador","Safa hidrostàtica./ Zafa hidrostática","Ganxo automàtic./ Gancho automático"],"c":2},{"q":"Cap a quina banda posarem el timó per deslliurar l’hèlix, si navegant observem la caiguda d’un/a tripulant a l’aigua? / ¿Hacia qué banda meteremos el timón para librar la hélice, si navegando observamos la caída de un/a tripulante al agua?","a":["A la d’estribord. / A la de estribor.","A la mateixa de caiguda del/de la tripulant. / A la misma de caída del tripulante.","A la contrària de caiguda del/de la tripulant. / A la contraria de caída del tripulante.","A la de babord. / A la de babor."],"c":1},{"q":"Segons el Reial Decret 1727/2007, de 21 de desembre quin comportament haurem de seguir en cas d’albirar un grup de cetacis? / ¿Según el Real decreto 1727/2007, de 21 de diciembre que comportamiento deberemos seguir en caso de avistar un grupo de cetáceos?","a":["Ens acostarem el màxim possible, sense causar danys als animals, per poder observar-los. / Nos acercaremos lo máximo posible, sin causar daños a los animales, para poder observar-los.","Seguirem a rumb i produirem sorolls i senyals lumíniques per tal que s’apartin i evitar la col·lisió. / Seguiremos a rumbo y produciremos ruidos y señales lumínicas para evitar la colisión.","A menys de 500 metres navegarem a una velocitat màxima de 4 nusos, no produirem cap soroll i no ens acostarem a menys de 60 metres dels cetacis. / A menos de 500 metros navegaremos a una velocidad máxima de 4 nudos, no produciremos ningún ruido y no nos acercaremos a menos de 60 metros de los cetáceos.","Augmentarem la velocitat del vaixell per apartar-los de la nostra derrota / Aumentaremos la velocidad de la embarcación para apartar-los de nuestra derrota."],"c":2},{"q":"En cas d’observar, durant la navegació, una bandera Alfa o una bandera Bravo modificada, ¿quina distància mínima de resguard haurem de deixar? / ¿En caso de observar, durante la navegación, una bandera Alfa o una bandera Bravo modificada, qué distancia mínima de reguardo deberemos dejar?","a":["100 metres i velocitat màxima de tres nusos en un radi de 200 metres / 100 metros i velocidad máxima de tres nudos en un radio de 200 metros.","A excepció de l’embarcació de recolzament de les tasques de busseig, totes les embarcacions i bucs hauran de mantenir -se a una distància mínima de 25 metres / A excepción de la embarcación de apoyo de los trabajos de buceo, todos los buques y embarcaciones deberán mantenerse a una distancia mínima de 25 metros","A excepció de l’embarcació de recolzament de les tasques de busseig, totes les embarcacions i bucs hauran de mantenir -se a una distància mínima de 50 metres. / A excepción de la embarcación de apoyo de los trabajos de buceo, todos los buques y embarcaciones deberán mantenerse a una distancia mínima de 50 metros.","15 metres en cas que hi hagi capbussadors en superfície. / 15 metros en caso que haya buceadores en superficie."],"c":2},{"q":"De quin color és el llum de les marques cardinals? / ¿De qué color es la luz de las marcas cardinales?","a":["Blanc i vermell. / Blanca y roja.","Vermell. / Roja.","Groc. / Amarilla.","Blanc. / Blanca."],"c":3},{"q":"Quina marca de cap de color negre del sistema cardinal ens indica “aigües navegables al quadrant Sud”? / ¿Qué marca de tope de color negro del sistema cardinal nos indica “aguas navegables en el cuadrante Sur”?","a":["Dos cons amb els vèrtexs cap avall. / Dos conos con los vértices hacia abajo.","Dos cons amb els vèrtexs oposats. / Dos conos con los vértices opuestos.","Dos cons amb els vèrtexs cap amunt. / Dos conos con los vértices hacia arriba.","Dos cons oposats per les seves bases. / Dos conos opuestos por sus bases."],"c":0},{"q":"Quina és la marca de topall de la boia que ens indica una instal·lació d’aqüicultura? / ¿Cuál es la marca de tope de la boya que nos indica una instalación de acuicultura?","a":["Dos cons negres / Dos conos negros","Una aspa groga en forma d’ics / Una aspa amarilla en forma de equis","Dues esferes negres / Dos esferas negras","Una esfera vermella / Una esfera roja"],"c":1},{"q":"Navegant al rumb oest, observem per la proa una boia groga i negra que com a marca de cap té dos cons negres sobreposats, amb els vèrtexs cap amunt. Quina maniobra haurem d’efectuar? / Navegando al rumbo oeste, observamos por la proa una boya amarilla y negra que tiene como marca de tope dos conos negros superpuestos, con los vértices hacia arriba. ¿Qué maniobra deberemos efectuar?","a":["Caurem a babord per poder passar pel Sud de la marca. / Caeremos a babor para poder pasar por el Sur de la marca.","La deixarem per la banda d’estribord. / La dejaremos por la banda de estribor.","La esquivarem perquè senyalitza un perill aïllat / La esquivaremos porqué señaliza un peligro aislado.","Caurem a estribord per passar pel Nord de la boia. / Caeremos a estribor para pasar por el Norte de la boya."],"c":3},{"q":"Què ens indica un llum blanc que ens trobem a la mar fent sis centellejos més una llampada llarga cada quinze segons? / ¿Qué nos indica una luz blanca que nos encontramos en la mar haciendo seis centelleos más un destello largo cada quince segundos?","a":["El quadrant oest d’un perill és el navegable. / El cuadrante oeste de un peligro es el navegable.","El quadrant sud d’un perill és el navegable. / El cuadrante sur de un peligro es el navegable.","Aigües navegables per estribord del llum. / Aguas navegables por estribor de la luz.","Aigües navegables per babord del llum. / Aguas navegables por babor de la luz."],"c":1},{"q":"Quines marques ha de portar un vaixell sense govern? / ¿Qué marcas deberá llevar un buque sin gobierno?","a":["Una bola negra i un con negre amb el vèrtex cap avall. / Una bola negra y un cono negro con el vértice hacia abajo.","Una bola negra. / Una bola negra.","Dues boles negres en línia vertical. / Dos bolas negras en línea vertical.","Tres boles negres en línia vertical. / Tres bolas negras en línea vertical."],"c":2},{"q":"Com es considera, segons el RIPA, la situació de l’embarcació \"A\" respecte a l’embarcació \"B\" del dibuix? / ¿Cómo se considera, según el RIPA, la situación de la embarcación \"A\" respecto de la embarcación \"B\" del dibujo?","a":["Embarcació que segueix a rumb. / Embarcación que sigue a rumbo.","Rumb oposat. / De vuelta encontrada.","Embarcació que abasta. / Embarcación que alcanza.","De volta creuada. / De vuelta cruzada."],"c":2},{"q":"Què haurà de fer el vaixell que té preferència en una situació d’encreuament? / ¿Qué deberá hacer el buque que tiene preferencia en una situación de cruce?","a":["Canviar el rumb una quarta a popa de l’altre vaixell. / Cambiar el rumbo una cuarta a popa del otro buque.","Canviar el rumb a la banda contrària d’on estigui l’altre vaixell. / Cambiar el rumbo a la banda contraria de donde esté el otro buque.","Disminuir la velocitat fins que l’altre vaixell estigui en franquia. / Disminuir la velocidad hasta que el otro buque esté en franquía.","Mantenir el rumb i la velocitat. / Mantener el rumbo y la velocidad."],"c":3},{"q":"Quin, d’aquests tipus d’embarcació, exhibeix els llums del dibuix? / ¿Cuál, de estos tipos de embarcación, exhibe las luces del dibujo?","a":["Un vaixell de pesca vist de proa. / Un buque de pesca visto de proa.","Un vaixell sense govern amb arrancada / Un sin gobierno con arrancada.","Un remolcador vist de proa. / Un remolcador visto de proa.","Un vaixell dedicat al practicatge en servei. / Un buque dedicado al practicaje en servicio."],"c":2},{"q":"Quina maniobra pot ser la més eficaç, i per tant de primera elecció per evitar l’abordatge, sempre que hi hagi prou espai? / ¿Qué maniobra puede ser la más eficaz, y por tanto la de primera elección para evitar el abordaje, siempre que haya el espacio suficiente?","a":["L’augment de velocitat. / El aumento de velocidad.","Un canvi de rumb. / Un cambio de rumbo.","La disminució de la velocitat. / La disminución de la velocidad.","Donar enrere. / Dar atrás."],"c":1},{"q":"Navegant en un iot a motor se’ns apropa per la nostra banda de babord, a rumb de col·lisió, un vaixell que té un màstil i dues veles hissades i també porta la marca del dibuix. Qui haurà de maniobrar i per què? / Navegando en un yate a motor se nos acerca por nuestra banda de babor, a rumbo de colisión, una embarcación que tiene un mástil y dos velas izadas y también lleva la marca del dibujo. ¿Quién deberá maniobrar y por qué?","a":["Nosaltres, ja que l’altre és un vaixell remolcat. / Nosotros, ya que el otro es un buque remolcado.","L’altre vaixell, perquè navega a vela i a motor a la vegada . / El otro buque, porque navega a vela y a motor simultáneamente.","Nosaltres perquè l’altre vaixell té les veles desplegades. / Nosotros porqué el otro barco tiene las velas desplegadas.","Nosaltres ja que l’altre vaixell és un pesquer / Nosotros ya que el otro barco es un pesquero."],"c":3},{"q":"Per a determinar la velocitat de seguretat, quin d’aquests factors, entre d’altres, es tindrà en compte? / ¿Para determinar la velocidad de seguridad, ¿cuál de estos factores, entre otros, se tendrá en cuenta?","a":["L’eslora del vaixell. / La eslora del barco.","L’obra morta. / La obra muerta.","La potència del motor. / La potencia del motor.","El calat, en relació amb la profunditat disponible d’aigua. / El calado, en relación con la profundidad disponible de agua."],"c":2},{"q":"Quins llums ha d’exhibir un vaixell fondejat de 120 m d’eslora? / ¿Qué luces ha de exhibir un buque fondeado de 120 m de eslora?","a":["Dos llums blancs de tot horitzó, un a proa i l’altre a popa. / Dos luces blancas todo horizonte, una en proa y la otra en popa.","Un llum blanc de tot horitzó al lloc més visible. / Una luz blanca todo horizonte en el lugar más visible.","Dos llums blancs de tot horitzó, un a proa i l’altre a popa, més els seus llums de treball o equivalents per a il·luminar la coberta. / Dos luces blancas todo horizonte, una en proa y la otra en popa, más sus luces de trabajo o equivalentes para iluminar sus cubiertas.","Un llum blanc intermitent per la banda on té la cadena. / Una luz blanca intermitente por la banda donde tiene la cadena."],"c":0},{"q":"Quin vaixell haurà de maniobrar en una situació d’encreuament entre un vaixell de vela i un dedicat a la pesca? / ¿Qué buque deberá maniobrar en una situación de cruce entre un buque de vela y uno dedicado a la pesca?","a":["El de vela. / El de vela.","El dedicat a la pesca. / El dedicado a la pesca.","El que creua per babord. / El que cruza por babor.","El que rep el vent per babord. / El que recibe el viento por babor."],"c":0},{"q":"Quants segons, aproximadament, ha de durar una xiulada curta segons el RIPA? / ¿Cuántos segundos de duración, aproximadamente, debe tener una pitada corta según el RIPA?","a":["3.","1.","De 4 a 6.","5."],"c":1},{"q":"Cap a quin costat hem de posar la pala del timó amb l’embarcació en arrencada enrere si volem que la pro a caigui a estribord? / ¿Hacia qué costado debemos poner la pala del timón con la embarcación en arrancada atrás si queremos que la proa caiga a estribor?","a":["Estribord. / Estribor.","Sobrevent. / Barlovento.","Babord. / Babor.","Sotavent. / Sotavento."],"c":2},{"q":"Què significa el verb ciavogar? ¿Qué significa el verbo ciabogar?","a":["Mantenir el rumb. / Mantener el rumbo.","Girar una embarcació dins del menor espai possible. / Girar una embarcación en el menor espacio posible.","Canviar 360º el rumb. / Cambiar 360º el rumbo.","Posar la proa al vent. / Poner la proa al viento."],"c":1},{"q":"Quina precaució prendrem a l’hora d’utilitzar les bengales? / ¿Qué precaución tomaremos a la hora de utilizar las bengalas?","a":["Mostrar-les sempre per babord. / Mostrarlas siempre por babor.","Mostrar-les per sotavent. / Mostrarlas por sotavento.","Mostrar-les per la proa. / Mostrarlas por la proa.","Mostrar-les per sobrevent. / Mostrarlas por barlovento."],"c":1},{"q":"Com s’apaga un incendi per sufocació? / ¿Cómo se apaga un incendio por sofocación?","a":["Eliminant el combustible. / Eliminando el combustible.","Trencant la reacció en cadena. / Rompiendo la reacción en cadena.","Eliminant el CO2. / Eliminando el CO2.","Eliminant l’oxigen. / Eliminando el oxígeno."],"c":3},{"q":"Quines aixetes haurem de tancar després d’haver atracat l’embarcació per tal de garantir-ne l’estanquitat? / ¿Qué grifos deberemos cerrar después de atracar la embarcación para garantizar su estanqueidad?","a":["Les de fons. / Los de fondo.","Les de balanç. / Los de balance.","Les d’oli. / Los de aceite.","Les de combustible. / Los de combustible."],"c":0},{"q":"Quina escala utilitzarem per saber la intensitat de l’estat de la mar en relació amb l’altura de les onades? / ¿Qué escala utilizaremos para saber el estado de la mar en relación con la altura de las olas?","a":["L’escala de Celsius / La escala de Celsius","L’escala de Beafort / La escala de Beafort","L’escala de Ritcher/ La escala de Ritcher","L’escala de Douglas / La escala de Douglas"],"c":3},{"q":"Com giren els vents a l’hemisferi nord al voltant dels centres d’altes pressions? / ¿Cómo giran los vientos en el hemisferio norte alrededor de los centros de altas presiones?","a":["En sentit horari. / En sentido horario.","En sentit contrari a les agulles del rellotge. / En sentido contrario a las agujas del reloj.","De nord a sud. / De norte a sur.","D’oest a est. / De oeste a este."],"c":0},{"q":"L’acció que fa el vent quan canvia de direcció s’anomena? ¿La acción que hace el viento cuando cambia de dirección se llama?","a":["Caure / Caer","Rolar / Rolar","Refrescar / Refrescar","Rodar / Rodar"],"c":1},{"q":"Amb quin nom es coneixen les brises costaneres? / ¿Con qué nombre se conocen las brisas costeras?","a":["De mar i d’interior. / De mar y de interior.","Costanera i de mar. / Costera y de mar.","Brisa marina i local. / Brisa marina y local.","Marinada i terral. / Virazón y terral."],"c":3},{"q":"Si naveguem proa a un far, quina serà la nostra marcació respecte a aquest far? / ¿Si navegamos proa a un faro, cuál será nuestra marcación respecto a este faro?","a":["90º / 90º","El rumb verdader més la correcció total / El rumbo verdadero más la corrección total","270º / 270º","0º / 0º"],"c":3},{"q":"Què és l’amplitud de la marea? / ¿Qué es la amplitud de la marea?","a":["És la diferència d’altures entre una baixamar i una plenamar consecutives / Es la diferencia de alturas entre una bajamar y una pleamar consecutivas.","És el temps transcorregut entre des de una baixamar fins la plenamar següent / Es el tiempo transcurrido entre una bajamar hasta la pleamar siguiente","És la distància, mesurada en milles nàutiques, que ha bufat un vent en una direcció sense obstacles / Es la distancia, medida en millas náuticas, que ha soplado un viento en una dirección sin obstáculos.","És el temps, expressat en hores, durant el qual ha estat bufant el vent en un lloc determinat. / Es el tiempo, expresado en horas, durante el cual ha estado soplando el viento en un lugar determinado."],"c":0},{"q":"A quin rumb circular correspon el rumb quadrantal S24W ? / ¿A qué rumbo circular corresponde el rumbo cuadrantal S24W?","a":["24º","204º","276º","336º"],"c":1},{"q":"A la rosa de declinació magnètica d’una carta posa 3° 20' W 2015 (10’E). Quina declinació magnètica tindrem al 2026? / En la rosa de declinación magnética de una carta pone 3° 20' W 2015 (10'E). ¿Qué declinación magnética tendremos en 2026?","a":["1,5ºW","3º 02’W","2° 08' W","51’ W"],"c":0},{"q":"Com s’anomenen les circumferències menors paral·leles a l’Equador? / ¿Cómo se denominan las circunferencias menores paralelas al Ecuador?","a":["Eixos de la esfera terràqüia / Ejes de la esfera terráquea.","Pols Nord i Sud / Polos Norte y Sur","Meridians / Meridiano.","Paral·lels / Paralelos"],"c":3},{"q":"El dia 23 de maig de 2026 ens trobem navegant a la zona de l’Estret de Gibraltar. A HRB= 09 :14 prenem demora verdadera del far de Cap Espartel, Dv= 122º i distància del mateix de 3,2 milles nàutiques. Estem navegant a 5 nusos. Volem arribar a un punt situat al Nord verdader del far de Punta Cires i a una distància de 2,8 mille s nàutiques. A quina hora del rellotge de Bitàcola estimada arribarem? El día 23 de mayo de 2026 nos encontramos navegando en la zona del Estrecho de Gibraltar. A HRB= 09:14 tomamos demora verdadera del faro de Cabo Espartel, Dv= 122º y distancia del mismo de 3,2 millas náuticas. Estamos navegando a 5 nudos. Queremos llegar a un punto situado al Norte verdadero del faro de Punta Cires y a una distancia de 2,8 millas náuticas. ¿A qué hora del reloj de Bitácora estimada llegaremos?","a":["HRB= 13:54","HRB= 14:55","HRB= 14:26","HRB= 15:32"],"c":2},{"q":"Als inicis de la primavera de 2026 ens trobem a l’oposició de Punta Almina i Punta Europa. En aquest moment prenem demora verdadera de Punta Carnero, Dv= 285º. Quina és la nostra situació? En los inicios de la primavera de 2026 nos encontramos navegando en la oposición de Punta Almina y Punta Europa. En este momento tomamos demora verdadera de Punta Carnero, Dv= 285º. ¿Cuál es nuestra posición?","a":["l= 36º 05,8N – L=005º 22,2’W","l= 36º 04,8N – L=005º 27,8’W","l= 36º 03,4N – L=005º 19,7’W","l= 36º 04,8N – L=005º 16,8’W"],"c":2},{"q":"Sent HRB =13:00 del dia 21 de maig de 2026 estem situats a l’oposició dels fars de Barbate i Punta Gracia. En el mateix moment prenem demora d’agulla del far de Punta Gracia, Da= S40E. Quin és el valor de la correcció total (Ct)? Siendo HRB = 13:00 del día 21 de mayo de 2026 estamos situados en la oposición de los faros de Barbate y Punta Gracia. En el mismo momento tomamos demora de aguja del faro de Punta Gracia, Da= S40E. ¿Cuál es el valor de la corrección total (Ct)?","a":["CT= -4º","CT= 0º","CT= -1º","CT= 5º"],"c":0},{"q":"El dia 27 de maig tenim previst salpar per tornar cap a Palamós. Sortirem del port de Ceuta des d’un lloc o n la sonda carta és de 4 metres, aprofitarem la primera plenamar i la previsió meteorològica anuncia que tindrem una pressió atmosfèrica de 1028 mil·libars. Quina sonda moment tindrem? / El día 27 de mayo de 2026 tenemos previsto zarpar para volver a Palamós. Partiremos del puerto de Ceuta en un lugar donde la sonda carta es de 4 metros, aprovecharemos la primera pleamar para partir y la previsión meteorológica anuncia que tendremos una presión atmosférica de 1028 milibares. ¿Qué sonda momento tendremos?","a":["Sm= 5,5m","Sm= 2,94m","Sm=4,79m","Sm=3,94m"],"c":2}]}];
